using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change 1: Cosmos provider no longer supports indexes (they are
        // managed server-side). Remove HasIndex calls or the model will throw.
        // modelBuilder.Entity<Blog>().HasIndex(b => b.Name);  // REMOVED

        // Breaking change 2: The discriminator property was renamed from
        // "Discriminator" to "$type" in EF Core 9. Existing documents still
        // store "Discriminator", so we must explicitly preserve the old name.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change 3: The id property format changed from
        // "EntityName|KeyValue" to just "KeyValue" in EF Core 9. Existing
        // documents use the old format, so we must opt back in to it.
        modelBuilder.Entity<Blog>().HasPartitionKey(b => b.Id);
        modelBuilder.Entity<Blog>().Property(b => b.Id)
            .ToJsonProperty("id")
            .HasValueGenerator<LegacyCosmosIdGenerator>();
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; }

    // Breaking change 4: EF Core 9 uses patch-based (partial) updates by default
    // instead of full-document replace. For existing apps that read-modify-save
    // whole documents, opt out by overriding SaveChanges or configuring the model.
    // See SyncJob.cs for the fix.
}

