using Microsoft.EntityFrameworkCore;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // BREAKING CHANGE 1 – HasIndex() removed for Cosmos provider.
        // Cosmos manages indexes server-side; EF Core 9 throws if you call HasIndex.
        // FIX: delete the call entirely.
        // was: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);

        // BREAKING CHANGE 2 – Discriminator property renamed "$type".
        // Existing documents store "Discriminator". Preserve the old property name.
        modelBuilder.Entity<Blog>()
            .HasDiscriminator<string>("Discriminator");

        // BREAKING CHANGE 3 – id format changed from "Blog|1" to just "1".
        // Existing documents use the old format. Preserve it so queries still
        // find existing data by telling EF to include the discriminator in the id.
        modelBuilder.Entity<Blog>()
            .HasDiscriminatorInJsonId();
    }
}

class Blog
{
    public string Id { get; set; }
    public string Name { get; set; }
}

